import { useQuery } from "@tanstack/react-query";
import { fetchItems } from "../api/items";

export const useItems = () => {
  return useQuery({
    queryKey: ["items"],
    queryFn: fetchItems,
    staleTime: 1000 * 60 * 5,
  });
};
